const items = $input.all();
const results = [];

for (const item of items) {

  const mainData = item.json.data?.[0] || {};
  const included = item.json.included || [];

  // get lookalike company IDs
  const lookalikeIds = mainData.relationships?.lookalike_companies?.data || [];

  for (const rel of lookalikeIds) {

    // match ID with included array
    const match = included.find(c => c.id === rel.id);

    if (!match) continue;

    const domain = match.attributes?.domain || '';

    // skip invalid / empty domains
    if (!domain) continue;

    results.push({
      json: {
        domain: domain,
        company_name: match.attributes?.company_name || '',
        source_domain: mainData.attributes?.domain || '',
        similarity_score: 0.9, 
      }
    });
  }
}

return results;

const items = $input.all();
const results = [];

const now = new Date();
const thirtyDaysAgo = new Date(now - 30 * 24 * 60 * 60 * 1000);

// Growth categories (IMPORTANT)
const positiveSignals = [
  'launches',
  'partners_with',
  'integrates_with',
  'acquires',
  'hires',
  'invests_into',
  'signs_new_client'
];

const negativeSignals = [
  'has_issues_with',
  'files_suit_against'
];

for (const item of items) {

  const data = item.json.data || [];

  let growthSignals = [];
  let negativeEvents = [];
  let recentSignals = [];

  for (const event of data) {
    const attr = event.attributes || {};
    const category = attr.category || '';
    const date = attr.found_at ? new Date(attr.found_at) : null;

    // Recent filter (last 30 days)
    const isRecent = date && date > thirtyDaysAgo;

    // Positive signals
    if (positiveSignals.includes(category)) {
      growthSignals.push({
        category,
        summary: attr.summary || '',
        date: attr.found_at
      });

      if (isRecent) {
        recentSignals.push(category);
      }
    }

    // Negative signals
    if (negativeSignals.includes(category)) {
      negativeEvents.push({
        category,
        summary: attr.summary || ''
      });
    }
  }

  // Score logic
  let growth_score = 0;

  growth_score += recentSignals.length * 2; // recent signals strong
  growth_score += growthSignals.length;     // total signals

  if (negativeEvents.length > 0) {
    growth_score -= negativeEvents.length * 2; // penalize
  }

  results.push({
    json: {
      growth_signal_count: growthSignals.length,
      recent_signal_count: recentSignals.length,
      negative_signal_count: negativeEvents.length,

      growth_signal_categories: [...new Set(growthSignals.map(s => s.category))],

      growth_signal_summary: growthSignals
        .slice(0, 3)
        .map(s => s.summary)
        .join(' | '),

      growth_score: growth_score,

      is_high_growth: growth_score >= 5,

      analyzed_at: now.toISOString()
    }
  });
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {

  const now = new Date();
  const thirtyDaysAgo = new Date(now - 30 * 24 * 60 * 60 * 1000);

  // node outputs
  const newsRes = $('Retrieve Company News Events').first().json;
  const jobsRes = $('Retrieve Company Job Openings').first().json;
  const techRes = $('Retrieve Technologies').first().json;

  const lookalike = $('Loop Lookalikes').first().json;

  const news = newsRes.data || [];
  const jobs = jobsRes.data || [];
  const tech = techRes.data || [];
  const included = techRes.included || [];

  let score = 0;

  // +30 Recent News
  const recentNews = news.filter(n => {
    const date = n.attributes?.found_at;
    return date && new Date(date) > thirtyDaysAgo;
  });

  if (recentNews.length > 0) score += 30;

  // +30 Hiring
  const jobCount = jobs.length;
  if (jobCount >= 5) score += 30;

  // FIXED TECH NAME RESOLUTION
  const targetTech = ['hubspot', 'salesforce', 'marketo'];

  // map techId -> actual name
  const techMap = {};
  for (const inc of included) {
    if (inc.type === 'technology') {
      techMap[inc.id] = (inc.attributes?.name || '').toLowerCase();
    }
  }

  // extract real tech names
  const techNames = tech.map(t => {
    const techId = t.relationships?.technology?.data?.id;
    return techMap[techId] || '';
  }).filter(Boolean);

  const techMatch = targetTech.some(t =>
    techNames.some(name => name.includes(t))
  );

  if (techMatch) score += 20;

  // +10 similarity
  const similarityScore = lookalike.similarity_score || 0;
  if (similarityScore > 0.7) score += 10;

  // country
  let country = '';
  const locEvent = news.find(n => n.attributes?.location_data?.length);
  if (locEvent) {
    country = locEvent.attributes.location_data[0]?.country || '';
  }

  // +10 region
  const targetRegions = ['United States', 'United Kingdom', 'Canada'];
  if (targetRegions.includes(country)) score += 10;

  results.push({
    json: {
      domain: lookalike.domain || '',
      company_name: lookalike.company_name || '',
      source_domain: lookalike.source_domain || '',
      similarity_score: similarityScore,
      news_count: recentNews.length,
      job_count: jobCount,
      tech_names: techNames.join(', '),
      tech_match: techMatch,
      composite_score: score,
      scored_at: now.toISOString()
    }
  });
}

return results;

const company = $json.company_name;
const domain = $json.domain;
const score = $json.composite_score;

// SAFE email generation (fix for your error)
const recipientEmail = domain ? `contact@${domain}` : '';

const prompt = `Write a short B2B cold email.

Company: ${company}
Domain: ${domain}
Lead Score: ${score}

Context:
- This company is similar to our best customers
- Shows strong buying signals (hiring, news, tech)

Write a concise outreach email (max 120 words)
Include:
- Personalized intro
- Mention growth signals
- CTA for quick call

Format:
Subject: ...
Body: ...`;

return [{
  json: {
    ...$json,
    ai_prompt: prompt,
    recipient_email: recipientEmail
  }
}];

